import { col as _col } from "./col";
import { presets } from "./presets";
import { deserializeSchema, serializeSchema } from "./serialize";
import { validateSchema } from "./validate";

/**
 * Column builder factories and presets for defining table schemas.
 *
 * **Primitive factories** — choose based on the data type of the column:
 * - `col.string()` — text data (`string`)
 * - `col.number()` — numeric data (`number`)
 * - `col.boolean()` — boolean data (`boolean`)
 * - `col.timestamp()` — date/time data (`Date`)
 * - `col.enum(values)` — string union (`T[number]`)
 * - `col.array(item)` — array of values (`U[]`)
 * - `col.record()` — key-value map (`Record<string, string>`)
 *
 * **Presets** — pre-configured builders for common log table patterns:
 * - `col.presets.logLevel(values)` — severity levels
 * - `col.presets.httpMethod(values)` — HTTP verbs
 * - `col.presets.httpStatus(codes?)` — HTTP status codes
 * - `col.presets.duration(unit?, slider?)` — timing / latency
 * - `col.presets.timestamp()` — sortable timestamp with timerange filter
 * - `col.presets.traceId()` — trace / request ID (code display, not filterable)
 * - `col.presets.pathname()` — URL path with text search
 *
 * @example
 * ```ts
 * import { col, createTableSchema } from "@/lib/table-schema";
 *
 * export const tableSchema = createTableSchema({
 *   level:   col.presets.logLevel(LEVELS).description("Log severity"),
 *   date:    col.presets.timestamp().label("Date").size(200).sheet(),
 *   latency: col.presets.duration("ms").label("Latency").sortable().size(110).sheet(),
 *   status:  col.presets.httpStatus().label("Status").size(60),
 *   method:  col.presets.httpMethod(METHODS).size(69),
 *   host:    col.string().label("Host").size(125).sheet(),
 *   headers: col.record().label("Headers").hidden().sheet(),
 * });
 * ```
 */
export const col = { ..._col, presets };
export type {
  ColBuilder,
  ColConfig,
  ColKind,
  ColumnDescriptor,
  DisplayConfig,
  FilterConfig,
  FilterDescriptor,
  FilterType,
  InferTableType,
  SchemaJSON,
  SheetConfig,
  SheetDescriptor,
  TableSchemaDefinition,
} from "./types";
export { generateColumns } from "./generators/columns";
export { generateFilterFields } from "./generators/filter-fields";
export { generateFilterSchema } from "./generators/filter-schema";
export { generateSheetFields } from "./generators/sheet-fields";
export { serializeSchema, deserializeSchema } from "./serialize";

/**
 * Derive defaultColumnVisibility from the schema.
 * Returns { [key]: false } for every column marked with .hidden().
 */
export function getDefaultColumnVisibility(
  schema: import("./types").TableSchemaDefinition,
): Record<string, boolean> {
  const visibility: Record<string, boolean> = {};
  for (const [key, builder] of Object.entries(schema)) {
    if (builder._config.hidden) {
      visibility[key] = false;
    }
  }
  return visibility;
}

/**
 * Create a table schema from a map of col.* builders.
 *
 * The returned object holds the definition and exposes:
 * - `toJSON()` — serializes the schema to a function-free JSON descriptor,
 *   suitable for AI agents, MCP tools, and `JSON.stringify`.
 *
 * Use `createTableSchema.fromJSON(json)` to reconstruct a schema from a
 * JSON descriptor (e.g. one generated by an AI agent). Custom renderers
 * (display.cell, filter.component, sheet.component) are not serialized and
 * must be applied manually on top of the reconstructed builders.
 *
 * @example
 * ```ts
 * export const tableSchema = createTableSchema({
 *   level: col.enum(LEVELS).label("Level").defaultOpen().sheet(),
 *   date: col.timestamp().label("Date").sortable().size(200).sheet(),
 * });
 *
 * export type ColumnSchema = InferTableType<typeof tableSchema.definition>;
 *
 * // Serialize for an AI agent or MCP tool
 * const json = tableSchema.toJSON();
 * // JSON.stringify(tableSchema) also works — toJSON() is called automatically
 *
 * // Reconstruct from AI-generated JSON
 * const schema = createTableSchema.fromJSON(json);
 * ```
 */
export function createTableSchema<
  T extends import("./types").TableSchemaDefinition,
>(definition: T): { definition: T; toJSON(): import("./types").SchemaJSON } {
  validateSchema(definition);
  return {
    definition,
    toJSON() {
      return serializeSchema(definition);
    },
  };
}

createTableSchema.fromJSON = (
  json: import("./types").SchemaJSON,
): {
  definition: import("./types").TableSchemaDefinition;
  toJSON(): import("./types").SchemaJSON;
} => {
  return createTableSchema(deserializeSchema(json));
};

import type { DatePreset, Option } from "@/components/data-table/types";
import type { JSX } from "react";

export type ColKind =
  | "string"
  | "number"
  | "boolean"
  | "timestamp"
  | "enum"
  | "array"
  | "record"
  | "select";

/** The set of filter UI types. Used as the `F` generic on `ColBuilder<T, F>`. */
export type FilterType = "input" | "checkbox" | "slider" | "timerange";

export type DisplayConfig =
  | { type: "text"; colorMap?: Record<string, string> }
  | { type: "code"; colorMap?: Record<string, string> }
  | { type: "boolean"; colorMap?: Record<string, string> }
  | { type: "star"; colorMap?: Record<string, string> }
  | { type: "badge"; colorMap?: Record<string, string> }
  | { type: "timestamp"; colorMap?: Record<string, string> }
  | { type: "number"; unit?: string; colorMap?: Record<string, string> }
  | {
      type: "bar";
      min?: number;
      max?: number;
      unit?: string;
      color?: string;
      colorMap?: Record<string, string>;
    }
  | {
      type: "heatmap";
      min?: number;
      max?: number;
      unit?: string;
      color?: string;
      colorMap?: Record<string, string>;
    }
  | {
      type: "gauge";
      min?: number;
      max?: number;
      unit?: string;
      color?: string;
      colorMap?: Record<string, string>;
    }
  | { type: "status-code"; colorMap?: Record<string, string> }
  | { type: "level-indicator"; colorMap?: Record<string, string> }
  | {
      type: "custom";
      cell: (value: unknown, row: unknown) => JSX.Element | null;
      colorMap?: Record<string, string>;
    };

export type FilterConfig = {
  type: FilterType;
  defaultOpen: boolean;
  commandDisabled: boolean;
  options?: Option[];
  component?: (props: Option) => JSX.Element | null;
  min?: number;
  max?: number;
  unit?: string;
  presets?: DatePreset[];
};

export type SheetConfig = {
  label?: string;
  component?: (row: unknown) => JSX.Element | null | string;
  condition?: (row: unknown) => boolean;
  className?: string;
  skeletonClassName?: string;
};

export type ColConfig = {
  kind: ColKind;
  enumValues?: readonly string[];
  arrayItem?: ColConfig;
  optional: boolean;
  label: string;
  description?: string;
  display: DisplayConfig;
  size?: number;
  hidden: boolean;
  enableHiding: boolean;
  hideHeader: boolean;
  resizable: boolean;
  sortable: boolean;
  filter: FilterConfig | null;
  sheet: SheetConfig | null;
};

/**
 * A fluent builder for a single table column.
 *
 * `T` — TypeScript type of the column's data value (inferred by `InferTableType`).
 * `F` — union of filter UI types valid for this col kind (compile-time constraint):
 *
 * | Factory            | Allowed filter types                    |
 * |--------------------|-----------------------------------------|
 * | `col.string()`     | `"input"`                               |
 * | `col.number()`     | `"input" \| "slider" \| "checkbox"`     |
 * | `col.boolean()`    | `"checkbox"`                            |
 * | `col.timestamp()`  | `"timerange"`                           |
 * | `col.enum()`       | `"checkbox"`                            |
 * | `col.array()`      | `"checkbox"`                            |
 * | `col.record()`     | `never` — `filterable()` is an error    |
 *
 * Calling `filterable(type)` with a type not in `F` is a **compile-time error**.
 */
export interface ColBuilder<T, F extends FilterType = FilterType> {
  /** @internal Raw column configuration. Used by generators — do not access directly. */
  readonly _config: ColConfig;

  /**
   * Sets the column header label shown in the table and filter sidebar.
   *
   * @example
   * col.string().label("Host")
   * col.enum(LEVELS).label("Severity")
   */
  label(text: string): ColBuilder<T, F>;

  /**
   * Attaches a human-readable description of the column's domain meaning.
   *
   * Not shown in the UI. Used by AI agents and MCP tools (via `toJSON()`) to
   * understand what the column represents.
   *
   * @example
   * col.number().label("Latency").description("Round-trip time from request to response, in ms")
   * col.enum(LEVELS).label("Level").description("Log severity: error > warn > info > debug")
   */
  description(text: string): ColBuilder<T, F>;

  /**
   * Sets how the column value is rendered in table cells.
   *
   * Built-in display types:
   * - `"text"` — plain text, truncated with tooltip on overflow
   * - `"code"` — monospace font (IDs, hashes, paths, hostnames)
   * - `"boolean"` — checkmark / dash icon
   * - `"badge"` — colored chip (enums, categories, tags)
   * - `"timestamp"` — relative time ("3m ago"), absolute datetime on hover
   * - `"number"` — formatted number with optional `unit` suffix
   * - `"bar"` — horizontal bar with `min`/`max` range and optional `unit`
   * - `"heatmap"` — background color intensity based on `min`/`max` range
   * - `"custom"` — developer-supplied JSX renderer (not serializable)
   *
   * @example
   * col.string().display("code")
   * col.number().display("number", { unit: "ms" })
   * col.number().display("bar", { min: 0, max: 5000, unit: "ms" })
   * col.number().display("heatmap", { min: 0, max: 100 })
   * col.enum(LEVELS).display("custom", { cell: (value) => <LevelBadge value={value} /> })
   */
  display(
    type:
      | "text"
      | "code"
      | "boolean"
      | "star"
      | "badge"
      | "timestamp"
      | "status-code"
      | "level-indicator",
    options?: { colorMap?: Record<string, string> },
  ): ColBuilder<T, F>;
  display(
    type: "number",
    options?: { unit?: string; colorMap?: Record<string, string> },
  ): ColBuilder<T, F>;
  display(
    type: "bar",
    options: {
      min: number;
      max: number;
      unit?: string;
      colorMap?: Record<string, string>;
    },
  ): ColBuilder<T, F>;
  display(
    type: "heatmap",
    options: {
      min: number;
      max: number;
      color?: string;
      colorMap?: Record<string, string>;
    },
  ): ColBuilder<T, F>;
  display(
    type: "custom",
    options: {
      cell: (value: unknown, row: unknown) => JSX.Element | null;
      colorMap?: Record<string, string>;
    },
  ): ColBuilder<T, F>;
  display(
    type: "heatmap" | "bar" | "gauge",
    options?: {
      min?: number;
      max?: number;
      unit?: string;
      color?: string;
    },
  ): ColBuilder<T, F>;

  /**
   * Enables filtering for this column using its default filter type.
   *
   * For `col.record()` (`F = never`) this is a **compile-time error**.
   * Use `.notFilterable()` on record columns instead (it is already the default).
   */
  filterable(...args: [F] extends [never] ? [never] : []): ColBuilder<T, F>;

  /**
   * Enables filtering with an explicit filter type and optional configuration.
   *
   * Only types in `F` are accepted — passing an invalid type is a **compile-time error**:
   * - `"input"` — free-text or number search field
   * - `"timerange"` — date range picker (with optional `presets`)
   * - `"checkbox"` — multi-select from a list of `options`
   * - `"slider"` — numeric range with required `min` / `max` bounds
   *
   * @example
   * col.string().filterable("input")
   * col.timestamp().filterable("timerange")
   * col.enum(LEVELS).filterable("checkbox", { options: LEVELS.map(v => ({ label: v, value: v })) })
   * col.number().filterable("slider", { min: 0, max: 5000 })
   */
  filterable(type: F & "input"): ColBuilder<T, "input">;
  filterable(
    type: F & "timerange",
    options?: { presets?: DatePreset[] },
  ): ColBuilder<T, "timerange">;
  filterable(
    type: F & "checkbox",
    options?: {
      options?: Option[];
      component?: (props: Option) => JSX.Element | null;
    },
  ): ColBuilder<T, "checkbox">;
  filterable(
    type: F & "slider",
    options: { min: number; max: number; unit?: string },
  ): ColBuilder<T, "slider">;

  /**
   * Removes filtering from this column.
   *
   * After calling `.notFilterable()`, subsequent `.filterable()` calls are
   * **compile-time errors** (`F` becomes `never`).
   *
   * @example
   * col.string().label("Request ID").notFilterable().hidden()
   */
  notFilterable(): ColBuilder<T, never>;

  /**
   * Opens the filter accordion for this column by default in the filter sidebar.
   *
   * Only applies to filterable columns. Use for high-priority filters that
   * users should see immediately without expanding the sidebar manually.
   *
   * @example
   * col.enum(LEVELS).label("Level").filterable("checkbox").defaultOpen()
   */
  defaultOpen(): ColBuilder<T, F>;

  /**
   * Excludes this column from the command palette filter search.
   *
   * Useful for columns whose filter state is managed elsewhere (e.g. a date
   * picker in the toolbar) or for UI-only state fields like `cursor`.
   *
   * @example
   * col.timestamp().label("Date").filterable("timerange").commandDisabled()
   */
  commandDisabled(): ColBuilder<T, F>;

  /**
   * Hides the column by default (not shown on first render).
   *
   * Hidden columns appear in the column visibility menu and can be toggled on.
   * Use `getDefaultColumnVisibility(schema)` to derive the initial visibility map.
   *
   * @example
   * col.number().label("DNS").filterable("slider", { min: 0, max: 5000 }).hidden()
   */
  hidden(): ColBuilder<T, F>;

  /**
   * Hides the column header label in the table while keeping the column visible.
   *
   * The label is still used in the filter sidebar and other UI elements.
   *
   * @example
   * col.enum(LEVELS).label("Level").hideHeader()
   */
  hideHeader(): ColBuilder<T, F>;

  /**
   * Enables column resizing via a drag handle in the header.
   *
   * Without this, `size` locks the column to a fixed width (`minSize === size`).
   * With this, the column can be freely resized; `size` becomes the initial width only.
   *
   * @example
   * col.string().label("Host").size(125).resizable()
   */
  resizable(): ColBuilder<T, F>;

  /**
   * Sets a fixed column width in pixels.
   *
   * Without `.resizable()`, both `size` and `minSize` are set to this value.
   * With `.resizable()`, only `size` is set (initial width), allowing free resizing.
   *
   * @example
   * col.enum(LEVELS).label("Level").size(27)
   * col.timestamp().label("Date").size(200)
   */
  size(px: number): ColBuilder<T, F>;

  /**
   * Enables click-to-sort on the column header.
   *
   * Renders a `DataTableColumnHeader` with ascending/descending/none sort controls.
   *
   * @example
   * col.timestamp().label("Date").sortable()
   * col.number().label("Latency").filterable("slider", { min: 0, max: 5000 }).sortable()
   */
  sortable(): ColBuilder<T, F>;

  /**
   * Marks the data field as potentially `undefined` in the row type.
   *
   * Changes `T` to `T | undefined` in the inferred schema type (`InferTableType`).
   * Use when the column field may be absent from some rows.
   *
   * @example
   * col.number().optional().label("Percentile").notFilterable().hidden()
   * col.string().optional().label("Message").notFilterable()
   */
  optional(): ColBuilder<T | undefined, F>;

  /**
   * Includes this column in the row detail drawer (`DataTableSheet`).
   *
   * Pass a `SheetConfig` to customize label, renderer, visibility condition,
   * and layout class. Calling `.sheet()` with no arguments uses defaults
   * (label from `.label()`, no custom renderer).
   *
   * @example
   * col.timestamp().label("Date").sheet()
   * col.string().label("Host").sheet({ skeletonClassName: "w-24" })
   * col.number().label("Latency").sheet({
   *   component: (row) => <>{row.latency}ms</>,
   *   skeletonClassName: "w-16",
   * })
   */
  sheet(config?: SheetConfig): ColBuilder<T, F>;

  /**
   * Marks the column as sheet-only: hidden, not filterable, and excluded
   * from the column visibility dropdown (`enableHiding: false`).
   *
   * Convenience for `.hidden().notFilterable()` + `enableHiding: false`.
   *
   * @example
   * col.record().label("Headers").sheetOnly().sheet({ ... })
   * col.string().optional().label("Message").sheetOnly().sheet({ ... })
   */
  sheetOnly(): ColBuilder<T, never>;
}

export type TableSchemaDefinition = Record<string, ColBuilder<unknown, any>>;

// Infer the data row type from a table schema definition
export type InferTableType<T extends TableSchemaDefinition> = {
  [K in keyof T]: T[K] extends ColBuilder<infer U, any> ? U : never;
};

// ── Serializable descriptors (function-free) ────────────────────────────────

export type FilterDescriptor = {
  type: FilterType;
  defaultOpen: boolean;
  commandDisabled: boolean;
  options?: Array<{ label: string; value: string | number | boolean }>;
  min?: number;
  max?: number;
};

export type SheetDescriptor = {
  label?: string;
  className?: string;
  skeletonClassName?: string;
};

/** Serializable display config — excludes the `custom` variant (contains JSX). */
export type SerializableDisplayConfig = Exclude<
  DisplayConfig,
  { type: "custom" }
>;

export type ColumnDescriptor = {
  key: string;
  label: string;
  description?: string;
  dataType: ColKind;
  enumValues?: readonly string[];
  arrayItemType?: { dataType: ColKind; enumValues?: readonly string[] };
  optional: boolean;
  hidden: boolean;
  hideHeader?: boolean;
  enableHiding?: boolean;
  sortable: boolean;
  size?: number;
  display: SerializableDisplayConfig;
  filter: FilterDescriptor | null;
  sheet: SheetDescriptor | null;
};

export type SchemaJSON = {
  columns: ColumnDescriptor[];
};

import type {
  ColBuilder,
  ColConfig,
  DisplayConfig,
  FilterConfig,
  FilterType,
  SheetConfig,
} from "./types";

function createColBuilder<T, F extends FilterType = FilterType>(
  config: ColConfig,
): ColBuilder<T, F> {
  // The implementation uses loose parameter types to satisfy all overload
  // signatures at once. TypeScript enforces the constraints at call sites
  // via the ColBuilder<T, F> interface overloads, not here.
  const builder = {
    get _config() {
      return config;
    },

    label(text: string): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, label: text });
    },

    description(text: string): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, description: text });
    },

    display(type: string, options?: Record<string, unknown>): ColBuilder<T, F> {
      const displayConfig = options
        ? ({ type, ...options } as DisplayConfig)
        : ({ type } as DisplayConfig);
      return createColBuilder<T, F>({ ...config, display: displayConfig });
    },

    filterable(
      type?: string,
      options?: Record<string, unknown>,
    ): ColBuilder<T, F> {
      const filterType = (type ||
        config.filter?.type ||
        "input") as FilterConfig["type"];
      const existing = config.filter;
      const sameType = filterType === existing?.type;
      const newFilter: FilterConfig = {
        type: filterType,
        defaultOpen: existing?.defaultOpen ?? false,
        commandDisabled: existing?.commandDisabled ?? false,
        // Preserve auto-derived options when filter type stays the same
        // and no explicit options are provided by the caller.
        ...(sameType && existing?.options ? { options: existing.options } : {}),
        ...(options ?? {}),
      };
      return createColBuilder<T, F>({ ...config, filter: newFilter });
    },

    notFilterable(): ColBuilder<T, never> {
      return createColBuilder<T, never>({ ...config, filter: null });
    },

    defaultOpen(): ColBuilder<T, F> {
      if (!config.filter) return createColBuilder<T, F>(config);
      return createColBuilder<T, F>({
        ...config,
        filter: { ...config.filter, defaultOpen: true },
      });
    },

    commandDisabled(): ColBuilder<T, F> {
      if (!config.filter) return createColBuilder<T, F>(config);
      return createColBuilder<T, F>({
        ...config,
        filter: { ...config.filter, commandDisabled: true },
      });
    },

    hidden(): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, hidden: true });
    },

    hideHeader(): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, hideHeader: true });
    },

    resizable(): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, resizable: true });
    },

    size(px: number): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, size: px });
    },

    sortable(): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, sortable: true });
    },

    optional(): ColBuilder<T | undefined, F> {
      return createColBuilder<T | undefined, F>({ ...config, optional: true });
    },

    sheet(sheetConfig?: SheetConfig): ColBuilder<T, F> {
      return createColBuilder<T, F>({ ...config, sheet: sheetConfig ?? {} });
    },

    sheetOnly(): ColBuilder<T, never> {
      return createColBuilder<T, never>({
        ...config,
        hidden: true,
        filter: null,
        enableHiding: false,
      });
    },
  } as ColBuilder<T, F>;

  return builder;
}

/**
 * A string column.
 *
 * - Data type: `string`
 * - Default display: `"text"` (plain text with overflow tooltip)
 * - Default filter: `"input"` (text search)
 * - Allowed filters: `"input"`
 *
 * @example
 * col.string().label("Host").size(125).sheet()
 * col.string().label("Message").notFilterable().optional().hidden()
 */
function string(): ColBuilder<string, "input"> {
  return createColBuilder<string, "input">({
    kind: "string",
    optional: false,
    label: "",
    display: { type: "text" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: { type: "input", defaultOpen: false, commandDisabled: false },
    sheet: null,
  });
}

/**
 * A numeric column.
 *
 * - Data type: `number`
 * - Default display: `"number"` (formatted, with optional unit)
 * - Default filter: `"input"` (exact match)
 * - Allowed filters: `"input"` | `"slider"` | `"checkbox"`
 *   - Use `"slider"` for continuous values (latency, file size)
 *   - Use `"checkbox"` for discrete values (HTTP status codes, port numbers)
 *
 * @example
 * col.number().label("Latency").display("number", { unit: "ms" }).filterable("slider", { min: 0, max: 5000 }).sortable()
 * col.number().label("Status").filterable("checkbox", { options: [{ label: "200", value: 200 }] })
 */
function number(): ColBuilder<number, "input" | "slider" | "checkbox"> {
  return createColBuilder<number, "input" | "slider" | "checkbox">({
    kind: "number",
    optional: false,
    label: "",
    display: { type: "number" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: { type: "input", defaultOpen: false, commandDisabled: false },
    sheet: null,
  });
}

/**
 * A boolean column.
 *
 * - Data type: `boolean`
 * - Default display: `"boolean"` (checkmark / dash icon)
 * - Default filter: `"checkbox"` with `true` / `false` options pre-wired
 * - Allowed filters: `"checkbox"`
 *
 * @example
 * col.boolean().label("Cache Hit").defaultOpen()
 */
function boolean(): ColBuilder<boolean, "checkbox"> {
  return createColBuilder<boolean, "checkbox">({
    kind: "boolean",
    optional: false,
    label: "",
    display: { type: "boolean" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: {
      type: "checkbox",
      defaultOpen: false,
      commandDisabled: false,
      options: [
        { label: "true", value: true },
        { label: "false", value: false },
      ],
    },
    sheet: null,
  });
}

/**
 * A timestamp column.
 *
 * - Data type: `Date`
 * - Default display: `"timestamp"` (relative time, absolute datetime on hover)
 * - Default filter: `"timerange"` (date range picker)
 * - Allowed filters: `"timerange"`
 *
 * @example
 * col.timestamp().label("Date").sortable().commandDisabled().size(200).sheet()
 */
function timestamp(): ColBuilder<Date, "timerange"> {
  return createColBuilder<Date, "timerange">({
    kind: "timestamp",
    optional: false,
    label: "",
    display: { type: "timestamp" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: { type: "timerange", defaultOpen: false, commandDisabled: true },
    sheet: null,
  });
}

/**
 * An enum column from a `readonly string[]` union.
 *
 * - Data type: `T[number]` (union of the provided string literals)
 * - Default display: `"badge"` (colored chip)
 * - Default filter: `"checkbox"` with options auto-derived from `values`
 * - Allowed filters: `"checkbox"`
 *
 * Checkbox options are auto-derived from `values` by default. Override them via
 * `.filterable("checkbox", { options: [...] })` when you need custom labels,
 * icons, or a subset of values.
 *
 * @param values - `as const` array of allowed string values
 *
 * @example
 * col.enum(LEVELS).label("Level").defaultOpen()
 * col.enum(LEVELS).label("Level").filterable("checkbox", {
 *   options: LEVELS.map(v => ({ label: v, value: v })), // override labels
 * })
 */
function colEnum<T extends readonly string[]>(
  values: T,
): ColBuilder<T[number], "checkbox"> {
  return createColBuilder<T[number], "checkbox">({
    kind: "enum",
    enumValues: values,
    optional: false,
    label: "",
    display: { type: "badge" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: {
      type: "checkbox",
      defaultOpen: false,
      commandDisabled: false,
      options: Array.from(values).map((v) => ({ label: v, value: v })),
    },
    sheet: null,
  });
}

/**
 * An array column, typically used for multi-value enum fields.
 *
 * - Data type: `U[]` where `U` is the item builder's type
 * - Default display: `"badge"` (colored chip per value)
 * - Default filter: `"checkbox"`
 * - Allowed filters: `"checkbox"`
 *
 * Most commonly used as `col.array(col.enum(values))` for tags / regions / labels.
 *
 * @param itemBuilder - A `ColBuilder` describing the array item type
 *
 * @example
 * col.array(col.enum(REGIONS)).label("Regions").filterable("checkbox", {
 *   options: REGIONS.map(r => ({ label: r, value: r })),
 * })
 */

function array<U>(
  itemBuilder: ColBuilder<U, any>,
): ColBuilder<U[], "checkbox"> {
  return createColBuilder<U[], "checkbox">({
    kind: "array",
    arrayItem: itemBuilder._config,
    optional: false,
    label: "",
    display: { type: "badge" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: { type: "checkbox", defaultOpen: false, commandDisabled: false },
    sheet: null,
  });
}

/**
 * A key-value record column.
 *
 * - Data type: `Record<string, string>`
 * - Default display: `"text"`
 * - Not filterable (`F = never`)
 *
 * Use for metadata maps, HTTP headers, environment variables, etc.
 * Typically rendered with a custom sheet component (key-value table / tabs).
 *
 * @example
 * col.record().label("Headers").hidden().sheet({
 *   component: (row) => <KVTabs data={row.headers} />,
 *   className: "flex-col items-start w-full gap-1",
 * })
 */
function record(): ColBuilder<Record<string, string>, never> {
  return createColBuilder<Record<string, string>, never>({
    kind: "record",
    optional: false,
    label: "",
    display: { type: "text" },
    hidden: false,
    enableHiding: true,
    hideHeader: false,
    resizable: false,
    sortable: false,
    filter: null,
    sheet: null,
  });
}

/**
 * A row-selection checkbox column.
 *
 * - Data type: `boolean` (selected state)
 * - Not filterable (`F = never`)
 * - Not shown in sheet or filters
 * - Renders a checkbox in both the header (select all) and each row
 *
 * @example
 * col.select().label("Select")
 */
function select(): ColBuilder<boolean, never> {
  return createColBuilder<boolean, never>({
    kind: "select",
    optional: false,
    label: "Select",
    display: { type: "boolean" },
    hidden: false,
    enableHiding: false,
    hideHeader: false,
    resizable: false,
    size: 40,
    sortable: false,
    filter: null,
    sheet: null,
  });
}

export const col = {
  string,
  number,
  boolean,
  timestamp,
  enum: colEnum,
  array,
  record,
  select,
};

import type { TableSchemaDefinition } from "./types";

/**
 * Validates a table schema definition and throws a descriptive error on the
 * first violation found.
 *
 * Called automatically by `createTableSchema()` — no need to call manually.
 *
 * Catches errors that the TypeScript type system cannot prevent:
 * - Missing label (`.label()` was never called)
 * - Slider `min` greater than `max`
 *
 * These checks run for both the TypeScript-authored path (`createTableSchema({...})`)
 * and the AI-generated path (`createTableSchema.fromJSON(json)`).
 */
export function validateSchema(definition: TableSchemaDefinition): void {
  for (const [key, builder] of Object.entries(definition)) {
    const c = builder._config;

    // 1. Label is required — col.* factories default to label: ""
    if (!c.label) {
      throw new Error(
        `[createTableSchema] Column "${key}" is missing a label.\n` +
          `  Fix: .label("${key[0]!.toUpperCase()}${key.slice(1)}")`,
      );
    }

    // 2. Number checkbox filter requires explicit options — the number factory
    //    has no value list to auto-derive from, so an empty options list would
    //    render a filter with no checkboxes (a silent no-op in the UI).
    if (
      c.kind === "number" &&
      c.filter?.type === "checkbox" &&
      (!c.filter.options || c.filter.options.length === 0)
    ) {
      throw new Error(
        `[createTableSchema] Column "${key}": checkbox filter on a number column requires explicit options.\n` +
          `  Fix: .filterable("checkbox", { options: [{ label: "200", value: 200 }, ...] })`,
      );
    }

    // 3. Slider bounds must be valid — type system requires { min, max } to be
    //    passed but cannot enforce min < max
    if (c.filter?.type === "slider") {
      const { min, max } = c.filter;
      if (min === undefined || max === undefined) {
        throw new Error(
          `[createTableSchema] Column "${key}": slider filter is missing min/max bounds.\n` +
            `  Fix: .filterable("slider", { min: 0, max: 100 })`,
        );
      }
      if (min > max) {
        throw new Error(
          `[createTableSchema] Column "${key}": slider min (${min}) must be less than max (${max}).\n` +
            `  Fix: swap the values — .filterable("slider", { min: ${max}, max: ${min} })`,
        );
      }
    }
  }
}

import { col } from "./col";
import type {
  ColBuilder,
  ColConfig,
  ColumnDescriptor,
  DisplayConfig,
  FilterDescriptor,
  SchemaJSON,
  SerializableDisplayConfig,
  SheetDescriptor,
  TableSchemaDefinition,
} from "./types";

// ── Serialization (schema → JSON) ────────────────────────────────────────────

function serializeFilter(filter: ColConfig["filter"]): FilterDescriptor | null {
  if (!filter) return null;
  const descriptor: FilterDescriptor = {
    type: filter.type,
    defaultOpen: filter.defaultOpen,
    commandDisabled: filter.commandDisabled,
  };
  if (filter.options) {
    descriptor.options = filter.options.map((o) => ({
      label: o.label,
      value: o.value as string | number | boolean,
    }));
  }
  if (filter.min !== undefined) descriptor.min = filter.min;
  if (filter.max !== undefined) descriptor.max = filter.max;
  // filter.component and filter.presets are functions/complex objects — stripped
  return descriptor;
}

function serializeSheet(sheet: ColConfig["sheet"]): SheetDescriptor | null {
  if (!sheet) return null;
  const descriptor: SheetDescriptor = {};
  if (sheet.label) descriptor.label = sheet.label;
  if (sheet.className) descriptor.className = sheet.className;
  if (sheet.skeletonClassName)
    descriptor.skeletonClassName = sheet.skeletonClassName;
  // sheet.component and sheet.condition are functions — stripped
  return descriptor;
}

function serializeDisplay(display: DisplayConfig): SerializableDisplayConfig {
  switch (display.type) {
    case "custom":
      // Custom renderers are not serializable — fall back to text
      return { type: "text" };
    case "number": {
      const d: SerializableDisplayConfig = { type: "number" };
      if (display.unit)
        (d as { type: "number"; unit?: string }).unit = display.unit;
      if (display.colorMap)
        (d as { colorMap?: Record<string, string> }).colorMap =
          display.colorMap;
      return d;
    }
    case "bar": {
      const d = { type: "bar" as const, min: display.min, max: display.max };
      return {
        ...d,
        ...(display.unit ? { unit: display.unit } : {}),
        ...(display.colorMap ? { colorMap: display.colorMap } : {}),
      };
    }
    case "heatmap": {
      const d: SerializableDisplayConfig = {
        type: "heatmap" as const,
        min: display.min,
        max: display.max,
      };
      if (display.unit) (d as { unit?: string }).unit = display.unit;
      if (display.color) (d as { color?: string }).color = display.color;
      if (display.colorMap)
        (d as { colorMap?: Record<string, string> }).colorMap =
          display.colorMap;
      return d;
    }
    case "gauge": {
      const d: SerializableDisplayConfig = {
        type: "gauge" as const,
        min: display.min,
        max: display.max,
      };
      if (display.unit) (d as { unit?: string }).unit = display.unit;
      if (display.color) (d as { color?: string }).color = display.color;
      return d;
    }
    default: {
      const d: SerializableDisplayConfig = { type: display.type };
      if (display.colorMap)
        (d as { colorMap?: Record<string, string> }).colorMap =
          display.colorMap;
      return d;
    }
  }
}

export function serializeSchema(definition: TableSchemaDefinition): SchemaJSON {
  const columns: ColumnDescriptor[] = Object.entries(definition).map(
    ([key, builder]) => {
      const c = builder._config;
      const descriptor: ColumnDescriptor = {
        key,
        label: c.label,
        dataType: c.kind,
        optional: c.optional,
        hidden: c.hidden,
        sortable: c.sortable,
        display: serializeDisplay(c.display),
        filter: serializeFilter(c.filter),
        sheet: serializeSheet(c.sheet),
      };
      if (c.description) descriptor.description = c.description;
      if (c.enumValues) descriptor.enumValues = c.enumValues;
      if (c.arrayItem) {
        descriptor.arrayItemType = {
          dataType: c.arrayItem.kind,
          ...(c.arrayItem.enumValues
            ? { enumValues: c.arrayItem.enumValues }
            : {}),
        };
      }
      if (c.size !== undefined) descriptor.size = c.size;
      if (c.hideHeader) descriptor.hideHeader = true;
      if (c.enableHiding === false) descriptor.enableHiding = false;
      return descriptor;
    },
  );
  return { columns };
}

// ── Deserialization (JSON → schema) ─────────────────────────────────────────
//
// Reconstructs col.* builders from a SchemaJSON descriptor.
// Limitation: custom renderers (display.cell, filter.component, sheet.component,
// sheet.condition) are not serialized and therefore cannot be reconstructed.
// Columns with display.type === "custom" fall back to the col kind's default
// display. Developers can override renderers on the returned builders.

export function deserializeSchema(json: SchemaJSON): TableSchemaDefinition {
  const definition: TableSchemaDefinition = {};

  for (const col_ of json.columns) {
    // 1. Pick the right col.* factory.
    // F is typed as `any` on the variable so we can call filterable() dynamically
    // without knowing the col kind at compile time — this is intentional since
    // deserializeSchema is a runtime operation reading from JSON.

    let builder: ColBuilder<unknown, any> =
      col_.dataType === "select"
        ? col.select()
        : col_.dataType === "enum" && col_.enumValues
          ? col.enum(col_.enumValues as readonly string[])
          : col_.dataType === "array" &&
              col_.arrayItemType?.dataType === "enum" &&
              col_.arrayItemType.enumValues
            ? col.array(
                col.enum(col_.arrayItemType.enumValues as readonly string[]),
              )
            : col_.dataType === "boolean"
              ? col.boolean()
              : col_.dataType === "timestamp"
                ? col.timestamp()
                : col_.dataType === "number"
                  ? col.number()
                  : col_.dataType === "record"
                    ? col.record()
                    : col.string();

    // 2. Label + description
    builder = builder.label(col_.label);
    if (col_.description) builder = builder.description(col_.description);

    // 3. Display
    const display = col_.display;
    if (display.type === "number") {
      const opts: { unit?: string; colorMap?: Record<string, string> } = {};
      if (display.unit) opts.unit = display.unit;
      if (display.colorMap) opts.colorMap = display.colorMap;
      builder = builder.display(
        "number",
        Object.keys(opts).length > 0 ? opts : undefined,
      );
    } else if (
      display.type === "bar" ||
      display.type === "heatmap" ||
      display.type === "gauge"
    ) {
      const opts: {
        min?: number;
        max?: number;
        unit?: string;
        color?: string;
      } = {};
      if (display.min !== undefined) opts.min = display.min;
      if (display.max !== undefined) opts.max = display.max;
      if (display.unit) opts.unit = display.unit;
      if (display.color) opts.color = display.color;
      builder = builder.display(
        display.type,
        Object.keys(opts).length > 0 ? opts : undefined,
      );
    } else if (
      display.type === "text" ||
      display.type === "code" ||
      display.type === "boolean" ||
      display.type === "star" ||
      display.type === "badge" ||
      display.type === "timestamp" ||
      display.type === "status-code" ||
      display.type === "level-indicator"
    ) {
      builder = builder.display(
        display.type,
        display.colorMap ? { colorMap: display.colorMap } : undefined,
      );
    }

    // 4. Filter
    if (col_.filter === null) {
      builder = builder.notFilterable();
    } else {
      const f = col_.filter;
      if (f.type === "slider" && f.min !== undefined && f.max !== undefined) {
        builder = builder.filterable("slider", { min: f.min, max: f.max });
      } else if (f.type === "checkbox") {
        builder = builder.filterable("checkbox", {
          ...(f.options ? { options: f.options } : {}),
        });
      } else if (f.type === "timerange") {
        builder = builder.filterable("timerange");
      } else {
        builder = builder.filterable("input");
      }
      if (f.defaultOpen) builder = builder.defaultOpen();
      if (f.commandDisabled) builder = builder.commandDisabled();
    }

    // 5. Structural modifiers
    // sheetOnly() sets both enableHiding: false AND hidden: true.
    // enableHiding: false alone (e.g. col.select()) should NOT trigger sheetOnly().
    if (col_.enableHiding === false && col_.hidden) {
      builder = builder.sheetOnly();
    } else if (col_.hidden) {
      builder = builder.hidden();
    }
    if (col_.hideHeader) builder = builder.hideHeader();
    if (col_.sortable) builder = builder.sortable();
    if (col_.optional) builder = builder.optional();
    if (col_.size !== undefined) builder = builder.size(col_.size);

    // 6. Sheet
    if (col_.sheet !== null) {
      builder = builder.sheet({
        ...(col_.sheet.label ? { label: col_.sheet.label } : {}),
        ...(col_.sheet.className ? { className: col_.sheet.className } : {}),
        ...(col_.sheet.skeletonClassName
          ? { skeletonClassName: col_.sheet.skeletonClassName }
          : {}),
      });
    }

    definition[col_.key] = builder;
  }

  return definition;
}

import type {
  ColumnDescriptor,
  FilterDescriptor,
  SchemaJSON,
  SerializableDisplayConfig,
} from "./types";

// Unix ms timestamps are 13-digit numbers (> Sep 2001, < Nov 2286)
const UNIX_MS_MIN = 1_000_000_000_000;
const UNIX_MS_MAX = 9_999_999_999_999;

function isIso8601(value: string): boolean {
  return (
    /^\d{4}-\d{2}-\d{2}(T[\d:.Z+\-]+)?$/.test(value) &&
    !isNaN(Date.parse(value))
  );
}

function isUnixMs(value: number): boolean {
  return (
    Number.isInteger(value) && value >= UNIX_MS_MIN && value <= UNIX_MS_MAX
  );
}

/** Convert camelCase, snake_case, or kebab-case key to a human-readable label. */
function keyToLabel(key: string): string {
  let label = key.replace(/[-_]/g, " ");
  label = label.replace(/([a-z])([A-Z])/g, "$1 $2");
  return label.replace(/\b\w/g, (c) => c.toUpperCase());
}

function displayForDataType(
  dataType: ColumnDescriptor["dataType"],
): SerializableDisplayConfig {
  switch (dataType) {
    case "number":
      return { type: "number" };
    case "boolean":
      return { type: "boolean" };
    case "timestamp":
      return { type: "timestamp" };
    case "enum":
    case "array":
      return { type: "badge" };
    case "string":
    case "record":
    case "select":
    default:
      return { type: "text" };
  }
}

function makeDescriptor(
  key: string,
  label: string,
  dataType: ColumnDescriptor["dataType"],
  filter: FilterDescriptor | null,
): ColumnDescriptor {
  return {
    key,
    label,
    dataType,
    optional: false,
    hidden: false,
    sortable: false,
    display: displayForDataType(dataType),
    filter,
    sheet: {},
  };
}

/** Split a key into lowercase words, handling camelCase, snake_case, and kebab-case. */
function keyToWords(key: string): string[] {
  return key
    .replace(/([a-z])([A-Z])/g, "$1_$2")
    .split(/[-_]/)
    .map((w) => w.toLowerCase())
    .filter(Boolean);
}

const ID_WORDS = new Set(["id", "uuid", "hash", "token", "key"]);
const CODE_WORDS = new Set([
  "path",
  "url",
  "uri",
  "endpoint",
  "route",
  "host",
  "link",
  "href",
  "website",
]);
const LATENCY_WORDS = new Set([
  "latency",
  "duration",
  "elapsed",
  "delay",
  "wait",
  "ttfb",
  "rtt",
  "ping",
]);
const SIZE_WORDS = new Set(["size", "bytes", "length"]);
const LEVEL_WORDS = new Set(["level", "severity"]);
const TRACE_ID_WORDS = new Set(["trace", "span", "request"]);
const FAVORITE_WORDS = new Set(["favorite", "starred", "bookmarked", "pinned"]);
const EMAIL_WORDS = new Set(["email", "mail"]);
const STATUS_WORDS = new Set(["status", "state"]);
const HEALTH_WORDS = new Set([
  "health",
  "score",
  "rating",
  "accuracy",
  "uptime",
]);
const PROGRESS_WORDS = new Set(["progress", "completion", "percentage"]);
const HP_WORDS = new Set(["hp", "hitpoints"]);

/** Semantic color mapping for status-like enum values. */
const STATUS_COLORS: Record<string, string> = {
  active: "#22c55e",
  completed: "#22c55e",
  success: "#22c55e",
  published: "#22c55e",
  approved: "#22c55e",
  pending: "#f59e0b",
  draft: "#f59e0b",
  inactive: "#f59e0b",
  paused: "#f59e0b",
  error: "#ef4444",
  failed: "#ef4444",
  rejected: "#ef4444",
  cancelled: "#ef4444",
  archived: "#6b7280",
  deleted: "#6b7280",
  disabled: "#6b7280",
};

/** Neutral palette for enum values without semantic meaning. */
const NEUTRAL_PALETTE = [
  "#6366f1",
  "#8b5cf6",
  "#ec4899",
  "#14b8a6",
  "#f97316",
  "#06b6d4",
  "#84cc16",
  "#eab308",
  "#ef4444",
  "#64748b",
];

/** Generate a colorMap for enum values, using semantic colors where possible. */
function generateColorMap(values: readonly string[]): Record<string, string> {
  const colorMap: Record<string, string> = {};
  let neutralIdx = 0;
  for (const value of values) {
    const lower = value.toLowerCase();
    if (STATUS_COLORS[lower]) {
      colorMap[value] = STATUS_COLORS[lower];
    } else {
      colorMap[value] = NEUTRAL_PALETTE[neutralIdx % NEUTRAL_PALETTE.length]!;
      neutralIdx++;
    }
  }
  return colorMap;
}

/** Post-process an inferred descriptor with smart display/config heuristics. */
function enhanceDescriptor(descriptor: ColumnDescriptor): ColumnDescriptor {
  const words = keyToWords(descriptor.key);
  const joined = words.join("");
  const d = { ...descriptor };

  const hasIdWord = words.some((w) => ID_WORDS.has(w));
  const hasCodeWord = words.some((w) => CODE_WORDS.has(w));
  const hasLatencyWord =
    words.some((w) => LATENCY_WORDS.has(w)) || joined.includes("responsetime");
  const hasSizeWord = words.some((w) => SIZE_WORDS.has(w));
  const hasLevelWord = words.some((w) => LEVEL_WORDS.has(w));
  const isTraceId = hasIdWord && words.some((w) => TRACE_ID_WORDS.has(w));
  const hasFavoriteWord = words.some((w) => FAVORITE_WORDS.has(w));
  const hasEmailWord = words.some((w) => EMAIL_WORDS.has(w));
  const hasStatusWord = words.some((w) => STATUS_WORDS.has(w));
  const hasHealthWord = words.some((w) => HEALTH_WORDS.has(w));
  const hasProgressWord = words.some((w) => PROGRESS_WORDS.has(w));
  const hasHpWord = words.some((w) => HP_WORDS.has(w));

  // ID-like columns → code display, not sortable
  if (hasIdWord) {
    d.display = { type: "code" };
    d.sortable = false;
    // Trace/span/request IDs → hidden, not filterable (matches col.presets.traceId())
    if (isTraceId) {
      d.hidden = true;
      d.filter = null;
    }
  }
  // Favorite/starred booleans → star display, hide column header
  else if (hasFavoriteWord && d.dataType === "boolean") {
    d.display = { type: "star" };
    d.hideHeader = true;
  }
  // Email columns → code display
  else if (hasEmailWord && d.dataType === "string") {
    d.display = { type: "code" };
  }
  // Path/URL-like columns → code display
  else if (hasCodeWord) {
    d.display = { type: "code" };
  }
  // Latency-like number columns → heatmap with ms unit, sortable
  else if (hasLatencyWord && d.dataType === "number") {
    d.display = {
      type: "heatmap",
      unit: "ms",
      min: d.filter?.min,
      max: d.filter?.max,
    };
    d.sortable = true;
  }
  // Size-like number columns → number with B unit, sortable
  else if (hasSizeWord && d.dataType === "number") {
    d.display = { type: "number", unit: "B" };
    d.sortable = true;
  }
  // Health/score/rating → gauge display (min always 0 for visual baseline)
  else if (hasHealthWord && d.dataType === "number") {
    d.display = { type: "gauge", min: 0, max: d.filter?.max };
    d.sortable = true;
  }
  // HP/hitpoints → bar display (min always 0 for visual baseline)
  else if (hasHpWord && d.dataType === "number") {
    d.display = { type: "bar", min: 0, max: d.filter?.max };
    d.sortable = true;
  }
  // Progress/completion → bar display (min always 0 for visual baseline)
  else if (hasProgressWord && d.dataType === "number") {
    d.display = { type: "bar", min: 0, max: d.filter?.max };
    d.sortable = true;
  }

  // Sortable defaults by type (unless ID-like)
  if (!hasIdWord) {
    if (d.dataType === "timestamp" || d.dataType === "number") {
      d.sortable = true;
    }
  }

  // Log level / severity enums: expand filter by default (matches col.presets.logLevel())
  if (hasLevelWord && d.dataType === "enum" && d.filter) {
    d.filter = { ...d.filter, defaultOpen: true };
  }

  // Status/state enums → semantic colorMap on badge display
  if (hasStatusWord && d.dataType === "enum" && d.enumValues) {
    d.display = { type: "badge", colorMap: generateColorMap(d.enumValues) };
  }

  // Column sizing defaults
  const sizeDefaults: Record<string, number> = {
    boolean: 100,
    timestamp: 220,
    number: 120,
    enum: 130,
  };
  if (sizeDefaults[d.dataType] !== undefined) {
    d.size = sizeDefaults[d.dataType];
  }

  return d;
}

function inferColDescriptor(key: string, values: unknown[]): ColumnDescriptor {
  const label = keyToLabel(key);
  const nonNull = values.filter((v) => v !== null && v !== undefined);

  if (nonNull.length === 0) {
    return makeDescriptor(key, label, "string", {
      type: "input",
      defaultOpen: false,
      commandDisabled: false,
    });
  }

  // Timestamp: ISO 8601 strings
  if (nonNull.every((v) => typeof v === "string" && isIso8601(v as string))) {
    return makeDescriptor(key, label, "timestamp", {
      type: "timerange",
      defaultOpen: false,
      commandDisabled: true,
    });
  }

  // Timestamp: Unix ms numbers
  if (nonNull.every((v) => typeof v === "number" && isUnixMs(v as number))) {
    return makeDescriptor(key, label, "timestamp", {
      type: "timerange",
      defaultOpen: false,
      commandDisabled: true,
    });
  }

  // Boolean
  if (nonNull.every((v) => v === true || v === false)) {
    return makeDescriptor(key, label, "boolean", {
      type: "checkbox",
      defaultOpen: false,
      commandDisabled: false,
    });
  }

  // Number
  if (nonNull.every((v) => typeof v === "number")) {
    const nums = nonNull as number[];
    const min = Math.min(...nums);
    const max = Math.max(...nums);
    const filter: FilterDescriptor =
      min !== max
        ? {
            type: "slider",
            defaultOpen: false,
            commandDisabled: false,
            min,
            max,
          }
        : { type: "input", defaultOpen: false, commandDisabled: false };
    return {
      ...makeDescriptor(key, label, "number", filter),
      display: { type: "number" },
    };
  }

  // Array
  if (nonNull.every((v) => Array.isArray(v))) {
    const allItems = (nonNull as unknown[][])
      .flat()
      .filter((v) => v !== null && v !== undefined);
    const allStrings =
      allItems.length > 0 && allItems.every((v) => typeof v === "string");
    if (allStrings) {
      const distinct = new Set(allItems as string[]);
      if (distinct.size <= 10) {
        const enumValues = Array.from(distinct);
        return {
          key,
          label,
          dataType: "array",
          arrayItemType: { dataType: "enum", enumValues },
          optional: false,
          hidden: false,
          sortable: false,
          display: { type: "badge" },
          filter: {
            type: "checkbox",
            defaultOpen: false,
            commandDisabled: false,
            options: enumValues.map((v) => ({ label: v, value: v })),
          },
          sheet: {},
        };
      }
    }
    // Non-enum array: not filterable
    return makeDescriptor(key, label, "array", null);
  }

  // Record (plain object, non-array)
  if (nonNull.every((v) => typeof v === "object" && !Array.isArray(v))) {
    return makeDescriptor(key, label, "record", null);
  }

  // String: check if enum (≤ 10 distinct values)
  if (nonNull.every((v) => typeof v === "string")) {
    const distinct = new Set(nonNull as string[]);
    if (distinct.size <= 10) {
      const enumValues = Array.from(distinct);
      return {
        key,
        label,
        dataType: "enum",
        enumValues,
        optional: false,
        hidden: false,
        sortable: false,
        display: { type: "badge" },
        filter: {
          type: "checkbox",
          defaultOpen: false,
          commandDisabled: false,
          options: enumValues.map((v) => ({ label: v, value: v })),
        },
        sheet: {},
      };
    }
    return makeDescriptor(key, label, "string", {
      type: "input",
      defaultOpen: false,
      commandDisabled: false,
    });
  }

  // Fallback: mixed or unrecognised types — warn and treat as string
  const types = [
    ...new Set(nonNull.map((v) => (Array.isArray(v) ? "array" : typeof v))),
  ];
  console.warn(
    `[inferSchemaFromJSON] Column "${key}" has mixed or ambiguous types (${types.join(", ")}). ` +
      `Falling back to string input filter.`,
  );
  return makeDescriptor(key, label, "string", {
    type: "input",
    defaultOpen: false,
    commandDisabled: false,
  });
}

/**
 * Infer a SchemaJSON from an array of plain data objects.
 *
 * Walks all rows, collects per-key values, and infers the best ColKind and
 * FilterType for each column using these heuristics:
 * - `timestamp`: ISO 8601 strings or Unix-ms numbers
 * - `boolean`: all values strictly true/false
 * - `number`: all non-null values are typeof "number"
 * - `enum`: strings with ≤ 10 distinct values across the sample
 * - `array`: values are arrays (item type inferred recursively)
 * - `record`: values are plain objects (non-array)
 * - `string`: fallback
 *
 * Number columns with min ≠ max get a "slider" filter; otherwise "input".
 */
export function inferSchemaFromJSON(data: unknown[]): SchemaJSON {
  if (!Array.isArray(data) || data.length === 0) {
    return { columns: [] };
  }

  // Collect all keys and their values across rows (preserving insertion order)
  const keyValues = new Map<string, unknown[]>();

  for (const row of data) {
    if (typeof row !== "object" || row === null || Array.isArray(row)) continue;
    for (const [key, value] of Object.entries(row as Record<string, unknown>)) {
      if (!keyValues.has(key)) keyValues.set(key, []);
      keyValues.get(key)!.push(value);
    }
  }

  const columns = Array.from(keyValues.entries()).map(([key, values]) =>
    enhanceDescriptor(inferColDescriptor(key, values)),
  );

  return { columns };
}

import type { ColumnDescriptor, SchemaJSON } from "./types";

interface PresetMatch {
  factory: string;
  skipDisplay: boolean;
  skipFilter: boolean;
  skipSortable: boolean;
}

/**
 * Detect whether a descriptor matches a known `col.presets.*` pattern.
 * Returns the preset factory call and which method chain steps it already covers.
 */
function detectPreset(c: ColumnDescriptor): PresetMatch | null {
  // traceId: string + code display + not filterable
  if (
    c.dataType === "string" &&
    c.display.type === "code" &&
    c.filter === null
  ) {
    return {
      factory: "col.presets.traceId()",
      skipDisplay: true,
      skipFilter: true,
      skipSortable: false,
    };
  }

  // timestamp + sortable → col.presets.timestamp()
  if (c.dataType === "timestamp" && c.sortable) {
    return {
      factory: "col.presets.timestamp()",
      skipDisplay: true,
      skipFilter: true,
      skipSortable: true,
    };
  }

  // duration: number + slider + number display → col.presets.duration(unit?, bounds?)
  if (
    c.dataType === "number" &&
    c.filter?.type === "slider" &&
    c.display.type === "number"
  ) {
    const unit = c.display.unit;
    const min = c.filter.min ?? 0;
    const max = c.filter.max ?? 100;
    const defaultBounds = min === 0 && max === 5000;
    const args: string[] = [];
    if (unit) {
      args.push(JSON.stringify(unit));
      if (!defaultBounds) args.push(`{ min: ${min}, max: ${max} }`);
    } else if (!defaultBounds) {
      args.push(`undefined, { min: ${min}, max: ${max} }`);
    }
    return {
      factory: `col.presets.duration(${args.join(", ")})`,
      skipDisplay: true,
      skipFilter: true,
      skipSortable: false,
    };
  }

  // logLevel: enum + badge + checkbox + defaultOpen
  if (
    c.dataType === "enum" &&
    c.enumValues &&
    c.filter?.type === "checkbox" &&
    c.filter?.defaultOpen &&
    c.display.type === "badge"
  ) {
    const vals = c.enumValues.map((v) => JSON.stringify(v)).join(", ");
    return {
      factory: `col.presets.logLevel([${vals}])`,
      skipDisplay: true,
      skipFilter: true,
      skipSortable: false,
    };
  }

  // httpStatus: number + number display + checkbox with all-numeric options
  if (
    c.dataType === "number" &&
    c.display.type === "number" &&
    c.filter?.type === "checkbox" &&
    c.filter?.options?.every((o) => typeof o.value === "number")
  ) {
    const codes = c.filter.options!.map((o) => o.value);
    return {
      factory: `col.presets.httpStatus([${codes.join(", ")}])`,
      skipDisplay: true,
      skipFilter: true,
      skipSortable: false,
    };
  }

  // httpMethod: enum + text + checkbox + !defaultOpen
  if (
    c.dataType === "enum" &&
    c.enumValues &&
    c.filter?.type === "checkbox" &&
    !c.filter?.defaultOpen &&
    c.display.type === "text"
  ) {
    const vals = c.enumValues.map((v) => JSON.stringify(v)).join(", ");
    return {
      factory: `col.presets.httpMethod([${vals}])`,
      skipDisplay: true,
      skipFilter: true,
      skipSortable: false,
    };
  }

  return null;
}

/**
 * Build the `col.*` factory call and method chain for one column descriptor.
 */
function buildChain(c: ColumnDescriptor): string {
  const parts: string[] = [];
  let skipDisplay = false;
  let skipFilter = false;
  let skipSortable = false;

  // 1. Factory (with preset detection)
  const preset = detectPreset(c);
  if (preset) {
    parts.push(preset.factory);
    skipDisplay = preset.skipDisplay;
    skipFilter = preset.skipFilter;
    skipSortable = preset.skipSortable;
  } else if (c.dataType === "enum" && c.enumValues) {
    const vals = c.enumValues.map((v) => JSON.stringify(v)).join(", ");
    parts.push(`col.enum([${vals}])`);
  } else if (
    c.dataType === "array" &&
    c.arrayItemType?.dataType === "enum" &&
    c.arrayItemType.enumValues
  ) {
    const vals = c.arrayItemType.enumValues
      .map((v) => JSON.stringify(v))
      .join(", ");
    parts.push(`col.array(col.enum([${vals}]))`);
  } else {
    parts.push(`col.${c.dataType}()`);
  }

  // 2. .label()
  parts.push(`.label(${JSON.stringify(c.label)})`);

  // 3. .description()
  if (c.description) {
    parts.push(`.description(${JSON.stringify(c.description)})`);
  }

  // 4. .display() — skip if covered by preset (unless colorMap needs emitting)
  if (!skipDisplay) {
    const display = c.display;
    const hasColorMap = !!display.colorMap;
    if (
      display.type === "heatmap" ||
      display.type === "bar" ||
      display.type === "gauge"
    ) {
      const opts: Record<string, unknown> = {};
      if (display.min !== undefined) opts.min = display.min;
      if (display.max !== undefined) opts.max = display.max;
      if (display.unit) opts.unit = display.unit;
      if (display.color) opts.color = display.color;
      parts.push(
        Object.keys(opts).length > 0
          ? `.display(${JSON.stringify(display.type)}, ${JSON.stringify(opts)})`
          : `.display(${JSON.stringify(display.type)})`,
      );
    } else if (display.type === "number" && (display.unit || hasColorMap)) {
      const opts: Record<string, unknown> = {};
      if (display.unit) opts.unit = display.unit;
      if (hasColorMap) opts.colorMap = display.colorMap;
      parts.push(`.display("number", ${JSON.stringify(opts)})`);
    } else if (hasColorMap) {
      parts.push(
        `.display(${JSON.stringify(display.type)}, ${JSON.stringify({ colorMap: display.colorMap })})`,
      );
    } else if (
      display.type !== "text" // "text" is the default for string/record, skip it
    ) {
      parts.push(`.display(${JSON.stringify(display.type)})`);
    }
  } else if (c.display.colorMap) {
    // Preset covers display type, but colorMap still needs to be emitted
    parts.push(
      `.display(${JSON.stringify(c.display.type)}, ${JSON.stringify({ colorMap: c.display.colorMap })})`,
    );
  }

  // 5. .filterable() / .notFilterable() — skip if covered by preset
  if (!skipFilter) {
    if (c.filter === null) {
      parts.push(`.notFilterable()`);
    } else {
      const f = c.filter;
      if (f.type === "slider" && f.min !== undefined && f.max !== undefined) {
        parts.push(`.filterable("slider", { min: ${f.min}, max: ${f.max} })`);
      } else if (f.type === "checkbox") {
        if (f.options && f.options.length > 0) {
          const opts = f.options
            .map(
              (o) =>
                `{ label: ${JSON.stringify(o.label)}, value: ${JSON.stringify(o.value)} }`,
            )
            .join(", ");
          parts.push(`.filterable("checkbox", { options: [${opts}] })`);
        } else {
          parts.push(`.filterable("checkbox")`);
        }
      } else if (f.type === "timerange") {
        parts.push(`.filterable("timerange")`);
      } else {
        parts.push(`.filterable("input")`);
      }

      if (f.defaultOpen) parts.push(`.defaultOpen()`);
      if (f.commandDisabled) parts.push(`.commandDisabled()`);
    }
  } else if (c.filter) {
    // Preset covers the filter, but still emit behavioral flags if set
    if (c.filter.defaultOpen) parts.push(`.defaultOpen()`);
    if (c.filter.commandDisabled) parts.push(`.commandDisabled()`);
  }

  // 6. Structural modifiers
  if (!skipSortable && c.sortable) parts.push(`.sortable()`);
  if (c.hidden) parts.push(`.hidden()`);
  if (c.optional) parts.push(`.optional()`);
  if (c.size !== undefined) parts.push(`.size(${c.size})`);

  // 7. .sheet()
  if (c.sheet !== null) {
    const sheetArgs: string[] = [];
    if (c.sheet.label)
      sheetArgs.push(`label: ${JSON.stringify(c.sheet.label)}`);
    if (c.sheet.className)
      sheetArgs.push(`className: ${JSON.stringify(c.sheet.className)}`);
    if (c.sheet.skeletonClassName)
      sheetArgs.push(
        `skeletonClassName: ${JSON.stringify(c.sheet.skeletonClassName)}`,
      );
    parts.push(
      sheetArgs.length > 0 ? `.sheet({ ${sheetArgs.join(", ")} })` : `.sheet()`,
    );
  }

  return parts.join("\n    ");
}

/**
 * Convert a `SchemaJSON` descriptor to a `createTableSchema(...)` TypeScript
 * source code string.
 *
 * The output is ready to copy-paste into a project that imports from
 * `@/lib/table-schema`.
 *
 * @example
 * ```ts
 * const ts = schemaToTypeScript(tableSchema.toJSON());
 * // → 'import { createTableSchema, col } from "@/lib/table-schema"; ...'
 * ```
 */
export function schemaToTypeScript(json: SchemaJSON): string {
  const lines: string[] = [
    'import { createTableSchema, col } from "@/lib/table-schema";',
    "",
    "export const schema = createTableSchema({",
  ];

  for (const descriptor of json.columns) {
    const chain = buildChain(descriptor);
    lines.push(`  ${descriptor.key}: ${chain},`);
  }

  lines.push("});");
  return lines.join("\n");
}

"use client";

import {
  DataTableCellBadge,
  DataTableCellBar,
  DataTableCellBoolean,
  DataTableCellCode,
  DataTableCellGauge,
  DataTableCellHeatmap,
  DataTableCellLevelIndicator,
  DataTableCellNumber,
  DataTableCellStar,
  DataTableCellStatusCode,
  DataTableCellText,
  DataTableCellTimestamp,
} from "@/components/data-table/data-table-cell";
import { DataTableColumnHeader } from "@/components/data-table/data-table-column-header";
import { Checkbox } from "@/components/ui/checkbox";
import type { ColumnDef } from "@tanstack/react-table";
import type { JSX } from "react";
import type { ColConfig, DisplayConfig, TableSchemaDefinition } from "../types";

/**
 * Derive the TanStack Table filterFn name from a column config.
 *
 * Custom filterFns (arrSome, inDateRange) must be registered on the table:
 *   filterFns: { inDateRange, arrSome }  // from src/lib/table/filterfns.ts
 */
function getFilterFn(config: ColConfig): string | undefined {
  if (!config.filter) return undefined;

  const { kind, filter, arrayItem } = config;

  switch (filter.type) {
    case "timerange":
      return "inDateRange"; // custom — must be registered
    case "slider":
      return "inNumberRange"; // TanStack built-in
    case "input":
      return "includesString"; // TanStack built-in; works for strings and numbers (via toString)
    case "checkbox":
      // Array columns use arrIncludesSome (checks row's array for filter values)
      if (kind === "array") return "arrIncludesSome"; // TanStack built-in
      // Single-value columns use arrSome (checks if row value is in filter array)
      return "arrSome"; // custom — must be registered
  }
}

/**
 * Render the cell based on the display config.
 */
function renderCell(
  display: DisplayConfig,
  value: unknown,
  row: unknown,
  context?: { min: number; max: number },
): JSX.Element | null {
  const fallback = <DataTableCellText value={String(value ?? "")} />;
  const colorMap = "colorMap" in display ? display.colorMap : undefined;
  switch (display.type) {
    case "text": {
      const hex = colorMap?.[String(value)];
      return typeof value === "string" || typeof value === "number" ? (
        <DataTableCellText value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "code": {
      const hex = colorMap?.[String(value)];
      return typeof value === "string" || typeof value === "number" ? (
        <DataTableCellCode value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "number": {
      const hex = colorMap?.[String(value)];
      return typeof value === "number" ? (
        <DataTableCellNumber value={value} unit={display.unit} color={hex} />
      ) : (
        fallback
      );
    }
    case "timestamp": {
      const hex = colorMap?.[String(value)];
      return value instanceof Date ||
        typeof value === "string" ||
        typeof value === "number" ? (
        <DataTableCellTimestamp date={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "badge": {
      if (Array.isArray(value)) {
        return (
          <div className="flex-no-wrap flex gap-1">
            {value.map((item, i) => (
              <DataTableCellBadge
                key={i}
                value={item}
                color={colorMap?.[String(item)]}
              />
            ))}
          </div>
        );
      }
      const hex = colorMap?.[String(value)];
      return typeof value === "string" || typeof value === "number" ? (
        <DataTableCellBadge value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "boolean": {
      const hex = colorMap?.[String(value)];
      return typeof value === "boolean" ? (
        <DataTableCellBoolean value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "star": {
      return typeof value === "boolean" ? (
        <DataTableCellStar value={value} />
      ) : (
        fallback
      );
    }
    case "status-code": {
      const hex = colorMap?.[String(value)];
      return typeof value === "number" ? (
        <DataTableCellStatusCode value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "level-indicator": {
      const hex = colorMap?.[String(value)];
      return typeof value === "string" ? (
        <DataTableCellLevelIndicator value={value} color={hex} />
      ) : (
        fallback
      );
    }
    case "custom":
      return display.cell(value, row);
    case "heatmap": {
      const { min = 0, max = 100 } = context ?? {};
      return typeof value === "number" ? (
        <DataTableCellHeatmap
          value={value}
          min={min}
          max={max}
          unit={display.unit}
          color={display.color}
        />
      ) : (
        fallback
      );
    }
    case "bar": {
      const { min = 0, max = 100 } = context ?? {};
      return typeof value === "number" ? (
        <DataTableCellBar
          value={value}
          min={min}
          max={max}
          unit={display.unit}
          color={display.color}
        />
      ) : (
        fallback
      );
    }
    case "gauge": {
      const { min = 0, max = 100 } = context ?? {};
      return typeof value === "number" ? (
        <DataTableCellGauge
          value={value}
          min={min}
          max={max}
          unit={display.unit}
          color={display.color}
        />
      ) : (
        fallback
      );
    }
  }
}

/**
 * Generate ColumnDef[] from a table schema definition.
 *
 * Rules:
 * - Dotted keys (e.g. "timing.dns") → id + accessorFn
 * - Non-dotted keys → accessorKey
 * - Sortable columns get DataTableColumnHeader; others get a plain string header
 * - filterFn is derived from col kind + filter type
 * - Cell renders via built-in display components or the "custom" cell function
 * - meta.label is always set; meta.hidden reflects .hidden() calls
 *
 * The consuming component must register custom filterFns:
 *   filterFns: { inDateRange, arrSome }
 *
 * Composite/virtual columns that span multiple fields must be appended manually:
 * @example
 * ```ts
 * const columns = [
 *   ...generateColumns(tableSchema),
 *   { id: "timing", header: ..., cell: ..., size: 130 },
 * ];
 * ```
 */
export function generateColumns<TData>(
  schema: TableSchemaDefinition,
): ColumnDef<TData>[] {
  return Object.entries(schema).map(([key, builder]) => {
    const config = builder._config;

    // Select column — checkbox header + cell
    if (config.kind === "select") {
      return {
        id: key,
        header: ({ table }) => (
          <div className="flex items-center justify-center">
            <Checkbox
              checked={
                table.getIsAllPageRowsSelected() ||
                (table.getIsSomePageRowsSelected() && "indeterminate")
              }
              onCheckedChange={(value) =>
                table.toggleAllPageRowsSelected(!!value)
              }
              aria-label="Select all"
              className="shadow-none"
            />
          </div>
        ),
        cell: ({ row }) => (
          <div
            className="flex items-center justify-center"
            onClick={(e) => e.stopPropagation()}
          >
            <Checkbox
              checked={row.getIsSelected()}
              onCheckedChange={(value) => row.toggleSelected(!!value)}
              aria-label="Select row"
              className="shadow-none"
            />
          </div>
        ),
        enableSorting: false,
        enableHiding: false,
        enableResizing: false,
        ...(config.size !== undefined
          ? { size: config.size, minSize: config.size, maxSize: config.size }
          : {}),
        meta: { label: config.label, kind: "select", hidden: false },
      } as ColumnDef<TData>;
    }

    const isDotted = key.includes(".");
    const filterFn = getFilterFn(config);

    const header = config.hideHeader
      ? () => <span className="sr-only">{config.label}</span>
      : config.sortable
        ? ({
            column,
          }: {
            column: Parameters<typeof DataTableColumnHeader>[0]["column"];
          }) => <DataTableColumnHeader column={column} title={config.label} />
        : config.label;

    const needsMinMax =
      config.display.type === "heatmap" ||
      config.display.type === "bar" ||
      config.display.type === "gauge";

    const cell = ({
      getValue,
      row,
      column,
    }: {
      getValue: () => unknown;
      row: { original: TData };
      column: { getFacetedMinMaxValues?: () => [number, number] | undefined };
    }) => {
      if (needsMinMax) {
        const display = config.display as {
          min?: number;
          max?: number;
        };
        const faceted = column.getFacetedMinMaxValues?.();
        const min = faceted?.[0] ?? display.min ?? 0;
        const max = faceted?.[1] ?? display.max ?? 100;
        return renderCell(config.display, getValue(), row.original, {
          min,
          max,
        });
      }
      return renderCell(config.display, getValue(), row.original);
    };

    const meta = {
      label: config.label,
      hidden: config.hidden,
      kind: config.kind,
    };

    const base = {
      header,
      cell,
      enableResizing: config.resizable,
      ...(config.enableHiding === false ? { enableHiding: false } : {}),
      ...(filterFn ? { filterFn } : {}),
      ...(config.size !== undefined
        ? {
            size: config.size,
            ...(config.resizable ? {} : { minSize: config.size }),
          }
        : {}),
      meta,
    };

    if (isDotted) {
      return {
        ...base,
        id: key,
        accessorFn: (row: TData) => (row as Record<string, unknown>)[key],
      } as ColumnDef<TData>;
    }

    return {
      ...base,
      accessorKey: key,
    } as ColumnDef<TData>;
  });
}

import type { DataTableFilterField } from "@/components/data-table/types";
import type { TableSchemaDefinition } from "../types";

/**
 * Generate DataTableFilterField[] from a table schema definition.
 *
 * Only includes fields where filter !== null.
 * Order follows schema definition order (JS object key insertion order).
 *
 * Options for checkbox fields are auto-derived from col.enum(values) or
 * col.boolean() if not explicitly provided via filterable("checkbox", { options }).
 */
export function generateFilterFields<TData>(
  schema: TableSchemaDefinition,
): DataTableFilterField<TData>[] {
  const result: DataTableFilterField<TData>[] = [];

  for (const [key, builder] of Object.entries(schema)) {
    const config = builder._config;
    if (!config.filter) continue;

    const { filter, label, kind, enumValues, arrayItem } = config;

    const base = {
      label,
      value: key as keyof TData,
      defaultOpen: filter.defaultOpen || undefined,
      commandDisabled: filter.commandDisabled || undefined,
    };

    switch (filter.type) {
      case "input": {
        result.push({ ...base, type: "input" });
        break;
      }
      case "timerange": {
        result.push({
          ...base,
          type: "timerange",
          presets: filter.presets,
        });
        break;
      }
      case "checkbox": {
        // Derive options if not explicitly provided
        let options = filter.options;
        if (!options) {
          if (kind === "enum" && enumValues) {
            options = enumValues.map((v) => ({ label: v, value: v }));
          } else if (kind === "boolean") {
            options = [
              { label: "Yes", value: true },
              { label: "No", value: false },
            ];
          } else if (
            kind === "array" &&
            arrayItem?.kind === "enum" &&
            arrayItem.enumValues
          ) {
            options = arrayItem.enumValues.map((v) => ({ label: v, value: v }));
          }
        }
        result.push({
          ...base,
          type: "checkbox",
          options,
          component: filter.component,
        });
        break;
      }
      case "slider": {
        const displayUnit =
          config.display.type === "number" && "unit" in config.display
            ? config.display.unit
            : undefined;
        result.push({
          ...base,
          type: "slider",
          min: filter.min ?? 0,
          max: filter.max ?? 100,
          unit: filter.unit ?? displayUnit,
        });
        break;
      }
    }
  }

  return result;
}

import {
  ARRAY_DELIMITER,
  RANGE_DELIMITER,
  SLIDER_DELIMITER,
} from "@/lib/delimiters";
import { createSchema, field } from "@/lib/store/schema";
import type {
  FieldBuilder,
  Schema,
  SchemaDefinition,
} from "@/lib/store/schema";
import type { ColBuilder, TableSchemaDefinition } from "../types";

/**
 * Extract keys from a TableSchemaDefinition where the column is filterable.
 * A column is filterable when its filter type `F` is not `never`.
 * Uses `[F] extends [never]` to avoid distribution issues with `any`.
 */
type FilterableKeys<T extends TableSchemaDefinition> = {
  [K in keyof T]: T[K] extends ColBuilder<infer _T, infer F>
    ? [F] extends [never]
      ? never
      : K
    : never;
}[keyof T];

// Extract T and F separately — TS struggles to infer both at once from ColBuilder
type GetColValue<B> = B extends ColBuilder<infer T, any> ? T : never;
type GetColFilter<B> = B extends ColBuilder<any, infer F> ? F : never;

/**
 * Map a single ColBuilder to the correct FieldBuilder type based on its
 * value type `T` and filter type `F`.
 */
type InferFilterFieldType<B> = [GetColFilter<B>] extends [never]
  ? never
  : GetColFilter<B> extends "input"
    ? GetColValue<B> extends string
      ? FieldBuilder<string | null>
      : GetColValue<B> extends number
        ? FieldBuilder<number | null>
        : FieldBuilder<unknown>
    : GetColFilter<B> extends "slider"
      ? FieldBuilder<(number | null)[]>
      : GetColFilter<B> extends "timerange"
        ? FieldBuilder<(Date | null)[]>
        : GetColFilter<B> extends "checkbox"
          ? GetColValue<B> extends (infer U)[]
            ? FieldBuilder<(U | null)[]>
            : FieldBuilder<(GetColValue<B> | null)[]>
          : FieldBuilder<unknown>;

/** The generated filter definition — preserves the filterable keys from `T`. */
type GeneratedFilterDef<T extends TableSchemaDefinition> = {
  [K in FilterableKeys<T>]: InferFilterFieldType<T[K]>;
};

function buildFilterDefinition(
  schema: TableSchemaDefinition,
): SchemaDefinition {
  const definition: SchemaDefinition = {};

  for (const [key, builder] of Object.entries(schema)) {
    const config = builder._config;
    if (!config.filter) continue;

    const { kind, filter, enumValues, arrayItem } = config;

    switch (filter.type) {
      case "input": {
        if (kind === "string") {
          definition[key] = field.string();
        } else if (kind === "number") {
          definition[key] = field.number();
        }
        break;
      }
      case "checkbox": {
        if (kind === "enum" && enumValues) {
          definition[key] = field.array(
            field.stringLiteral(enumValues as readonly string[]),
          );
        } else if (kind === "number") {
          definition[key] = field
            .array(field.number())
            .delimiter(ARRAY_DELIMITER);
        } else if (kind === "boolean") {
          definition[key] = field
            .array(field.boolean())
            .delimiter(ARRAY_DELIMITER);
        } else if (
          kind === "array" &&
          arrayItem?.kind === "enum" &&
          arrayItem.enumValues
        ) {
          definition[key] = field.array(
            field.stringLiteral(arrayItem.enumValues as readonly string[]),
          );
        }
        break;
      }
      case "slider": {
        definition[key] = field
          .array(field.number())
          .delimiter(SLIDER_DELIMITER);
        break;
      }
      case "timerange": {
        definition[key] = field
          .array(field.timestamp())
          .delimiter(RANGE_DELIMITER);
        break;
      }
    }
  }

  return definition;
}

/**
 * Generate a BYOS filter schema from a table schema definition.
 *
 * Each filterable column maps to the appropriate field.* builder:
 * - col.string()  + input    → field.string()
 * - col.number()  + input    → field.number()
 * - col.number()  + slider   → field.array(field.number()).delimiter(SLIDER_DELIMITER)
 * - col.number()  + checkbox → field.array(field.number()).delimiter(ARRAY_DELIMITER)
 * - col.boolean() + checkbox → field.array(field.boolean()).delimiter(ARRAY_DELIMITER)
 * - col.timestamp()+ timerange→ field.array(field.timestamp()).delimiter(RANGE_DELIMITER)
 * - col.enum(v)   + checkbox → field.array(field.stringLiteral(v))
 * - col.array(col.enum(v)) + checkbox → field.array(field.stringLiteral(v))
 *
 * Non-filterable fields are excluded. Pass `extraFields` for pagination,
 * sorting, and other non-filter state.
 *
 * @example
 * ```ts
 * // Without extra fields (filter fields only)
 * const filterSchema = generateFilterSchema(tableSchema.definition);
 *
 * // With extra fields (recommended)
 * const filterSchema = generateFilterSchema(tableSchema.definition, {
 *   sort: field.sort(),
 *   uuid: field.string(),
 *   live: field.boolean().default(false),
 *   size: field.number().default(40),
 * });
 * ```
 */
export function generateFilterSchema<T extends TableSchemaDefinition>(
  schema: T,
): Schema<GeneratedFilterDef<T>>;
export function generateFilterSchema<
  T extends TableSchemaDefinition,
  E extends SchemaDefinition,
>(schema: T, extraFields: E): Schema<GeneratedFilterDef<T> & E>;
export function generateFilterSchema<
  T extends TableSchemaDefinition,
  E extends SchemaDefinition,
>(schema: T, extraFields?: E) {
  const generated = buildFilterDefinition(schema);
  const merged = extraFields ? { ...generated, ...extraFields } : generated;
  return createSchema(merged);
}

import type { SheetField } from "@/components/data-table/types";
import type {
  ColConfig,
  SerializableDisplayConfig,
  TableSchemaDefinition,
} from "../types";

function defaultDisplayForKind(
  kind: ColConfig["kind"],
): SerializableDisplayConfig {
  switch (kind) {
    case "enum":
    case "array":
      return { type: "badge" };
    case "boolean":
      return { type: "boolean" };
    case "timestamp":
      return { type: "timestamp" };
    case "number":
      return { type: "number" };
    case "string":
    case "record":
    case "select":
    default:
      return { type: "text" };
  }
}

function getDisplayDescriptor(config: ColConfig): SerializableDisplayConfig {
  if (config.display.type === "custom") {
    return defaultDisplayForKind(config.kind);
  }
  return config.display as SerializableDisplayConfig;
}

/**
 * Generate SheetField[] from a table schema definition.
 *
 * Only includes fields where sheet !== null (.sheet() was called).
 * Sheet type is derived from the filter type, or "readonly" if not filterable.
 * Sheet label falls back to the column label if not overridden in .sheet({ label }).
 */
export function generateSheetFields<TData>(
  schema: TableSchemaDefinition,
): SheetField<TData>[] {
  const result: SheetField<TData>[] = [];

  for (const [key, builder] of Object.entries(schema)) {
    const config = builder._config;
    if (config.sheet === null) continue;

    const sheetConfig = config.sheet;
    const filterConfig = config.filter;

    // Derive sheet type from filter type, or "readonly" if not filterable
    const sheetType: SheetField<TData>["type"] =
      filterConfig?.type ?? "readonly";

    result.push({
      id: key as keyof TData,
      label: sheetConfig.label ?? config.label,
      type: sheetType,
      display: getDisplayDescriptor(config),
      component: sheetConfig.component as SheetField<TData>["component"],
      condition: sheetConfig.condition as SheetField<TData>["condition"],
      className: sheetConfig.className,
      skeletonClassName: sheetConfig.skeletonClassName,
    });
  }

  return result;
}

"use client";

// REMINDER: React Compiler is not compatible with Tanstack Table v8 https://github.com/TanStack/table/issues/5567
"use no memo";

import { DataTableFilterCommand } from "@/components/data-table/data-table-filter-command";
import { DataTableInfinite } from "@/components/data-table/data-table-infinite";
import { useDataTable } from "@/components/data-table/data-table-provider";
import { MemoizedDataTableSheetContent } from "@/components/data-table/data-table-sheet/data-table-sheet-content";
import { DataTableSheetDetails } from "@/components/data-table/data-table-sheet/data-table-sheet-details";
import type { SheetField } from "@/components/data-table/types";
import { useMemoryAdapter } from "@/lib/store/adapters/memory";
import { DataTableStoreProvider } from "@/lib/store/provider/DataTableStoreProvider";
import { field } from "@/lib/store/schema";
import type { SchemaDefinition } from "@/lib/store/schema/types";
import {
  createTableSchema,
  generateColumns,
  generateFilterFields,
  generateFilterSchema,
  generateSheetFields,
  getDefaultColumnVisibility,
} from "@/lib/table-schema";
import { inferSchemaFromJSON } from "@/lib/table-schema/infer";
import * as React from "react";

type AutoRow = Record<string, unknown>;

export interface DataTableAutoProps {
  data: AutoRow[];
}

export function DataTableAuto({ data }: DataTableAutoProps) {
  const schemaJson = React.useMemo(() => inferSchemaFromJSON(data), [data]);

  const { definition } = React.useMemo(
    () => createTableSchema.fromJSON(schemaJson),
    [schemaJson],
  );

  const columns = React.useMemo(
    () => generateColumns<AutoRow>(definition),
    [definition],
  );

  const filterFields = React.useMemo(
    () => generateFilterFields<AutoRow>(definition),
    [definition],
  );

  const sheetFields = React.useMemo(
    () => generateSheetFields<AutoRow>(definition),
    [definition],
  );

  const defaultColumnVisibility = React.useMemo(
    () => getDefaultColumnVisibility(definition),
    [definition],
  );

  const filterSchema = React.useMemo(() => {
    const generated = generateFilterSchema(definition);
    return {
      ...generated,
      definition: {
        ...generated.definition,
        sort: field.sort(),
      },
    };
  }, [definition]);

  const adapter = useMemoryAdapter(filterSchema.definition, { id: "auto" });

  return (
    <DataTableStoreProvider adapter={adapter}>
      <DataTableAutoInner
        data={data}
        columns={columns}
        filterFields={filterFields}
        sheetFields={sheetFields}
        defaultColumnVisibility={defaultColumnVisibility}
        schema={filterSchema.definition}
      />
    </DataTableStoreProvider>
  );
}

const noop = () => Promise.resolve();
const noopRefetch = () => {};

function DataTableAutoInner({
  data,
  columns,
  filterFields,
  sheetFields,
  defaultColumnVisibility,
  schema,
}: {
  data: AutoRow[];
  columns: React.ComponentProps<
    typeof DataTableInfinite<AutoRow, unknown>
  >["columns"];
  filterFields: React.ComponentProps<
    typeof DataTableInfinite<AutoRow, unknown>
  >["filterFields"];
  sheetFields: SheetField<AutoRow>[];
  defaultColumnVisibility: Record<string, boolean>;
  schema: SchemaDefinition;
}) {
  return (
    <DataTableInfinite
      columns={columns}
      data={data}
      filterFields={filterFields}
      defaultColumnVisibility={defaultColumnVisibility}
      totalRowsFetched={data.length}
      hasNextPage={false}
      fetchNextPage={noop}
      refetch={noopRefetch}
      isFetching={false}
      isLoading={false}
      tableId="auto"
      commandSlot={<DataTableFilterCommand schema={schema} tableId="auto" />}
      sheetSlot={
        <AutoSheetSlot sheetFields={sheetFields} totalRows={data.length} />
      }
      footerSlot={
        <div className="text-muted-foreground text-sm">
          powered by{" "}
          <a
            href="https://openstatus.dev"
            target="_blank"
            rel="noreferrer"
            className="text-foreground hover:text-primary"
          >
            openstatus.dev
          </a>
        </div>
      }
    />
  );
}

function AutoSheetSlot({
  sheetFields: fields,
  totalRows,
}: {
  sheetFields: SheetField<AutoRow>[];
  totalRows: number;
}) {
  const { table, rowSelection, isLoading, filterFields } = useDataTable<
    AutoRow,
    unknown
  >();
  const selectedRowKey = Object.keys(rowSelection)?.[0];
  const selectedRow = React.useMemo(() => {
    if (isLoading && !selectedRowKey) return undefined;
    return table
      .getCoreRowModel()
      .flatRows.find((row) => row.id === selectedRowKey);
  }, [selectedRowKey, isLoading, table]);

  return (
    <DataTableSheetDetails
      title={
        selectedRow ? String(Object.values(selectedRow.original)[0] ?? "") : ""
      }
      titleClassName="font-mono"
    >
      <MemoizedDataTableSheetContent
        table={table}
        data={selectedRow?.original}
        filterFields={filterFields}
        fields={fields}
        metadata={{
          totalRows,
          filterRows: totalRows,
          totalRowsFetched: totalRows,
        }}
      />
    </DataTableSheetDetails>
  );
}
